#!/bin/zsh
# Score a trial result against expected values.
# Usage: score.sh <task-id> <result-json-file>
# Output: JSON object with score (0, 0.5, 1), details of matches/mismatches.
#
# Static fields come from expected.json.
# Dynamic fields (e.g. calculator display) come from the .vars file
# generated by the harness alongside the result file.

set -euo pipefail

SCRIPT_DIR="$(cd "$(dirname "$0")" && pwd)"
EXPECTED_FILE="$SCRIPT_DIR/expected.json"

TASK_ID="${1:?Usage: score.sh <task-id> <result-json-file>}"
RESULT_FILE="${2:?Usage: score.sh <task-id> <result-json-file>}"

if [ ! -f "$RESULT_FILE" ]; then
    echo '{"score": 0, "reason": "result file not found"}'
    exit 0
fi

# Load dynamic expected values from .vars file if the task declares dynamic_fields
VARS_FILE="${RESULT_FILE%.json}.vars"
DYNAMIC_JSON="{}"
HAS_DYNAMIC=$(jq -r --arg t "$TASK_ID" '.[$t].dynamic_fields // [] | length' "$EXPECTED_FILE" 2>/dev/null || echo "0")
if [ "$HAS_DYNAMIC" -gt 0 ] && [ -f "$VARS_FILE" ]; then
    source "$VARS_FILE"
    if [ -n "${calc_expected:-}" ]; then
        DYNAMIC_JSON=$(jq -n --arg display "$calc_expected" '{display: $display}')
    fi
fi

jq -n \
    --arg task_id "$TASK_ID" \
    --slurpfile result "$RESULT_FILE" \
    --slurpfile expected "$EXPECTED_FILE" \
    --argjson dynamic "$DYNAMIC_JSON" \
'
    ($result[0]) as $r |
    ($expected[0][$task_id] // null) as $spec |

    # Early exits
    if $r.is_error == true then
        {score: 0, reason: "agent errored", matched: 0, total: 0, details: {}}
    elif ($r.result // "") == "" then
        {score: 0, reason: "no response from agent", matched: 0, total: 0, details: {}}
    elif $spec == null then
        {score: 0, reason: "no expected values for task", matched: 0, total: 0, details: {}}
    elif $spec.match_mode == "manual" then
        {score: -1, reason: "requires manual scoring", matched: 0, total: 0, details: {}}
    else
        # Parse "key: value" lines from the agent response
        ($r.result | split("\n") | map(
            capture("^(?<key>[a-z_]+):\\s*(?<val>.+)$") // empty
            | {key: .key, value: .val}
        ) | from_entries) as $agent_vals |

        $spec.match_mode as $mode |

        # Merge static fields from expected.json with dynamic fields from .vars
        (($spec.fields // {}) + $dynamic) as $all_expected |

        # Compare each expected field
        ($all_expected | to_entries | map(
            .key as $k | .value as $expected |
            ($agent_vals[$k] // "") as $actual |
            ($actual | gsub("^\\s+|\\s+$"; "")) as $actual_trimmed |
            (
                if $mode == "exact" then
                    ($actual_trimmed | ascii_downcase) == ($expected | ascii_downcase)
                else
                    # Numeric-aware contains: if both look like numbers, compare
                    # to 6 significant digits to handle display truncation/rounding.
                    # Otherwise fall back to substring containment.
                    if (($actual_trimmed | test("^-?[0-9]+(\\.[0-9]+)?$")) and ($expected | test("^-?[0-9]+(\\.[0-9]+)?$"))) then
                        (($actual_trimmed | tonumber) - ($expected | tonumber)) | fabs < (($expected | tonumber | fabs) * 0.00001)
                    else
                        (($actual_trimmed | ascii_downcase) | contains($expected | ascii_downcase))
                        or (($expected | ascii_downcase) | contains($actual_trimmed | ascii_downcase))
                    end
                end
            ) as $match |
            {key: $k, expected: $expected, actual: $actual_trimmed, match: $match}
        )) as $comparisons |

        ($comparisons | length) as $total |
        ([$comparisons[] | select(.match)] | length) as $matched |

        {
            score: (if $total == 0 then 0 elif $matched == $total then 1 elif $matched > 0 then 0.5 else 0 end),
            matched: $matched,
            total: $total,
            details: ($comparisons | map({(.key): {expected, actual, match}}) | add // {})
        }
    end
'
